#include <stdio.h>
#include <math.h>
typedef struct{float x,y,z;}V;
static V v(float x,float y,float z){V r={x,y,z};return r;}
static V ad(V a,V b){return v(a.x+b.x,a.y+b.y,a.z+b.z);}
static V sb(V a,V b){return v(a.x-b.x,a.y-b.y,a.z-b.z);}
static V ml(V a,float s){return v(a.x*s,a.y*s,a.z*s);}
static float dt(V a,V b){return a.x*b.x+a.y*b.y+a.z*b.z;}
static V nm(V a){float l=sqrtf(dt(a,a));return v(a.x/l,a.y/l,a.z/l);}
static V SC={0,-0.5f,-5.0f};
static float SR=1.0f,PY=-1.5f,AMB=0.2f;
static V L;
static int sph(V o,V d,float*t,V*n){
 V oc=sb(o,SC);
 float a=dt(d,d),b=2*dt(oc,d),c=dt(oc,oc)-SR*SR,D=b*b-4*a*c;
 if(D<0)return 0;
 float s=sqrtf(D),tt=(-b-s)/(2*a);
 if(!(tt>0.001f)){tt=(-b+s)/(2*a);if(!(tt>0.001f))return 0;}
 *t=tt;*n=nm(sb(ad(o,ml(d,tt)),SC));return 1;
}
static int pln(V o,V d,float*t){
 if(fabsf(d.y)<1e-4f)return 0;
 float tt=(PY-o.y)/d.y;
 if(!(tt>0.001f))return 0;
 *t=tt;return 1;
}
static V sky(V d){float t=0.5f*(d.y+1.0f);return ad(ml(v(1,1,1),1-t),ml(v(0.5f,0.7f,1.0f),t));}
static V trace(V o,V d){
 float st,pt;V sn,P,N;int issph;
 int sh=sph(o,d,&st,&sn),ph=pln(o,d,&pt);
 if(sh&&(!ph||st<pt)){P=ad(o,ml(d,st));N=sn;issph=1;}
 else if(ph){P=ad(o,ml(d,pt));N=v(0,1,0);issph=0;}
 else return sky(d);
 float df=dt(N,L);if(df<0)df=0;
 float t2;V n2;
 if(sph(ad(P,ml(N,0.001f)),L,&t2,&n2))df=0;
 float br=AMB+(1-AMB)*df;
 if(issph)return ml(v(1,0.2f,0.2f),br);
 int par=((int)(floorf(P.x)+floorf(P.z)))&1;
 return ml(par==0?v(0.9f,0.9f,0.9f):v(0.4f,0.4f,0.4f),br);
}
int main(void){
 int W=2400,H=1800,i,j;
 float vh=2.0f,vw=(float)W/H*vh;
 V O=v(0,0,0),hz=v(vw,0,0),vt=v(0,vh,0),ll=v(-vw/2,-vh/2,-1.0f);
 L=nm(v(1,1,-1));
 FILE*f=fopen("reconstructed.ppm","w");
 fprintf(f,"P3\n%d %d\n255\n",W,H);
 for(j=0;j<H;j++){
  float vv=(float)j/(H-1);
  for(i=0;i<W;i++){
   float u=(float)i/(W-1);
   V d=nm(ad(ad(ll,ml(hz,u)),ml(vt,1-vv)));
   V c=trace(O,d);
   float cx=c.x<0?0:c.x>1?1:c.x;
   float cy=c.y<0?0:c.y>1?1:c.y;
   float cz=c.z<0?0:c.z>1?1:c.z;
   fprintf(f,"%d %d %d\n",(int)(255.99f*cx),(int)(255.99f*cy),(int)(255.99f*cz));
  }
 }
 fclose(f);
 return 0;
}

